mapper.select:
select id, session_id, user_id, role, content, image_urls, model, prompt_tokens, completion_tokens,
       total_tokens, create_by, create_time, update_by, update_time, remark, deleted
from t_chat_message
where deleted = 0
  and user_id = #{userId}
  and session_id = #{sessionId}
order by id desc
limit #{limit}

select id, session_id, user_id, role, content, image_urls, model, prompt_tokens, completion_tokens,
       total_tokens, create_by, create_time, update_by, update_time, remark, deleted
from t_chat_message
where deleted = 0
  and user_id = #{userId}
  and session_id = #{sessionId}

  and id < #{lastId}

order by id desc
limit #{limit}
